import { Column, Heading, Text, Button } from "@once-ui-system/core";
import { home, baseURL } from "@/resources";
import { Projects } from "@/components/work/Projects";

export async function generateMetadata() {
  return {
    title: home.title,
    description: home.description,
    metadataBase: new URL(baseURL),
    openGraph: {
      title: home.title,
      description: home.description,
      url: `${baseURL}${home.path}`,
      images: [
        `${baseURL}/api/og/generate?title=${encodeURIComponent(home.title)}`,
      ],
    },
  };
}

export default function Home() {
  return (
    <Column fillWidth as="main" horizontal="center" gap="xl" paddingY="12">
      <Column fillWidth maxWidth="m" horizontal="center" gap="m" style={{ textAlign: "center" }}>
        {home.featured.display && (
          <Button
            href={home.featured.href}
            variant="secondary"
            size="s"
          >
            {home.featured.title}
          </Button>
        )}
        <Heading as="h1" variant="display-strong-xl">
          {home.headline}
        </Heading>
        <Text as="p" variant="body-default-xl" onBackground="neutral-weak">
          {home.subline}
        </Text>
      </Column>
      <Projects range={[1, 1]} />
    </Column>
  );
}
